import React, { useEffect } from 'react';
import { Translation } from '../i18n';

interface DiscountCelebrationProps {
  t: Translation;
  discountPercentage: number;
  savedAmount: number;
  onClose: () => void;
}

const DiscountCelebration: React.FC<DiscountCelebrationProps> = ({ t, discountPercentage, savedAmount, onClose }) => {
  useEffect(() => {
    const timer = setTimeout(onClose, 4000); // Auto close after 4s
    return () => clearTimeout(timer);
  }, [onClose]);

  return (
    <div className="fixed inset-0 flex items-center justify-center z-[100] pointer-events-none">
       {/* Backdrop */}
       <div className="absolute inset-0 bg-black/20 backdrop-blur-sm transition-opacity duration-300"></div>

       {/* Modal */}
       <div 
         onClick={onClose}
         className="bg-white rounded-2xl shadow-2xl p-8 transform animate-bounce-in relative z-10 pointer-events-auto text-center border-4 border-yellow-400 max-w-sm w-full mx-4 cursor-pointer"
         title="Click to close"
       >
          {/* Confetti Elements (Simple CSS) */}
          <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none">
             {[...Array(20)].map((_, i) => (
                <div key={i} className="confetti-piece" style={{ 
                    left: `${Math.random() * 100}%`, 
                    animationDelay: `${Math.random() * 0.5}s`,
                    backgroundColor: ['#ff0', '#f00', '#0f0', '#00f', '#f0f'][Math.floor(Math.random() * 5)]
                }}></div>
             ))}
          </div>

          <div className="mb-4 relative z-10">
             <span className="text-6xl animate-pulse inline-block">🎉</span>
          </div>
          <h2 className="text-3xl font-black text-slate-800 mb-2 relative z-10">
            {t.discountUnlockedTitle}
          </h2>
          <p className="text-xl text-slate-600 font-bold mb-4 relative z-10">
            {t.discountUnlockedMessage(discountPercentage)}
          </p>
          <div className="bg-green-100 text-green-800 px-4 py-2 rounded-full inline-block font-bold text-lg animate-pulse relative z-10 border border-green-200 shadow-sm">
            {t.youSaved(`$${savedAmount.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`)}
          </div>
       </div>

       <style>{`
         @keyframes popIn {
           0% { opacity: 0; transform: scale(0.5) translateY(20px); }
           60% { opacity: 1; transform: scale(1.1); }
           100% { opacity: 1; transform: scale(1); }
         }
         .animate-bounce-in {
           animation: popIn 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards;
         }
         .confetti-piece {
            position: absolute;
            width: 8px;
            height: 8px;
            top: -10px;
            opacity: 0;
            animation: fall 2.5s linear forwards;
         }
         @keyframes fall {
            0% { top: -10px; opacity: 1; transform: rotate(0deg); }
            100% { top: 110%; opacity: 0; transform: rotate(720deg); }
         }
       `}</style>
    </div>
  );
};
export default DiscountCelebration;

import React from 'react';
import PricingOption from './PricingOption';
import type { ServiceCategory } from '../types';
import type { Translation } from '../i18n';

interface PricingCategoryProps {
  category: ServiceCategory;
  selectedIds: string[];
  onServiceToggle: (optionId: string, category: ServiceCategory) => void;
  quantities: { [id: string]: number };
  onQuantityChange: (optionId: string, newQuantity: number) => void;
  language: 'ar' | 'en';
  t: Translation;
  isClientMode: boolean;
}

const PricingCategory: React.FC<PricingCategoryProps> = ({
  category,
  selectedIds,
  onServiceToggle,
  quantities,
  onQuantityChange,
  language,
  t,
  isClientMode,
}) => {
  return (
    <div className="bg-white rounded-2xl shadow-lg border border-slate-200/80 print:shadow-none print:border-0 overflow-hidden">
      <div className={`p-6 bg-slate-50/50 border-b border-slate-200/80 ${language === 'ar' ? 'text-right' : 'text-left'}`}>
        <h3 className="text-2xl font-bold text-slate-800">{category.name}</h3>
        {category.description && (
          <div 
            className="mt-2 text-md text-slate-600 leading-relaxed" 
            dangerouslySetInnerHTML={{ __html: category.description }} 
          />
        )}
      </div>

      <div className="p-6 space-y-4">
        {category.options.map((option) => (
          <PricingOption
            key={option.id}
            option={option}
            isSelected={selectedIds.includes(option.id)}
            onToggle={() => onServiceToggle(option.id, category)}
            quantity={quantities[option.id] || 1}
            onQuantityChange={(newQuantity) => onQuantityChange(option.id, newQuantity)}
            isRadio={category.isRadio}
            language={language}
            t={t}
            isClientMode={isClientMode}
          />
        ))}
      </div>
    </div>
  );
};

export default PricingCategory;

import React from 'react';
import type { ServiceOption } from '../types';
import { getUnitPrice } from '../constants';
import type { Translation } from '../i18n';

interface PricingOptionProps {
  option: ServiceOption;
  isSelected: boolean;
  onToggle: () => void;
  quantity: number;
  onQuantityChange: (newQuantity: number) => void;
  isRadio?: boolean;
  language: 'ar' | 'en';
  t: Translation;
  isClientMode: boolean;
}

const CheckIcon = ({ className = "h-4 w-4" }: { className?: string }) => (
    <svg className={className} viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
    </svg>
);

const QuantitySelector: React.FC<{
    quantity: number,
    onQuantityChange: (newQuantity: number) => void,
    t: Translation,
    label?: string,
}> = ({ quantity, onQuantityChange, t, label }) => {
    return (
        <div className="flex items-center gap-2" onClick={(e) => e.stopPropagation()}>
            <span className="text-sm font-medium text-slate-700">{label || t.pagesLabel}</span>
            <div className="flex items-center">
                <button
                    onClick={(e) => { e.stopPropagation(); onQuantityChange(quantity - 1); }}
                    disabled={quantity <= 1}
                    className="px-2 py-1 border border-slate-300 rounded-l-md text-slate-600 hover:bg-slate-100 disabled:opacity-50 transition-colors"
                    aria-label={t.decreaseQuantity}
                >
                    -
                </button>
                <span className="px-3 py-1 border-t border-b border-slate-300 text-slate-800 bg-white" aria-label={t.currentQuantity} role="status">{quantity}</span>
                <button
                    onClick={(e) => { e.stopPropagation(); onQuantityChange(quantity + 1); }}
                    className="px-2 py-1 border border-slate-300 rounded-r-md text-slate-600 hover:bg-slate-100 transition-colors"
                    aria-label={t.increaseQuantity}
                >
                    +
                </button>
            </div>
        </div>
    );
};


const PricingOption: React.FC<PricingOptionProps> = ({
  option,
  isSelected,
  onToggle,
  quantity,
  onQuantityChange,
  isRadio,
  language,
  t,
  isClientMode,
}) => {
    const selectorType = isRadio ? 'radio' : 'checkbox';
    const currentUnitPrice = getUnitPrice(option, quantity);
    const totalOptionPrice = currentUnitPrice * (option.hasQuantity ? quantity : 1);

    const handleToggle = () => {
        if (!isClientMode) {
            onToggle();
        }
    };

    return (
        <div
            onClick={handleToggle}
            className={`
                relative p-4 border rounded-xl transition-all duration-300 ease-[cubic-bezier(0.34,1.56,0.64,1)] transform
                ${isSelected
                    ? 'bg-blue-50 border-blue-500 shadow-lg scale-[1.02] ring-1 ring-blue-300 z-10'
                    : `bg-white border-slate-200 ${!isClientMode ? 'hover:border-blue-300 hover:shadow-md hover:scale-[1.01] hover:bg-slate-50' : ''}`
                }
                ${isClientMode ? 'cursor-default' : 'cursor-pointer'}
            `}
            role={selectorType}
            aria-checked={isSelected}
            aria-label={option.name}
            tabIndex={isClientMode ? -1 : 0}
            onKeyDown={(e) => { if (!isClientMode && (e.key === ' ' || e.key === 'Enter')) { e.preventDefault(); onToggle(); } }}
        >
            <div className="flex items-start gap-4">
                {/* Custom Checkbox/Radio */}
                <div className={`
                    flex-shrink-0 w-5 h-5 mt-1 border-2 flex items-center justify-center transition-all duration-300 ease-out
                    ${isRadio ? 'rounded-full' : 'rounded'}
                    ${isSelected ? 'bg-blue-600 border-blue-600 text-white scale-110 shadow-sm' : 'bg-white border-slate-300 group-hover:border-blue-400'}
                    ${isClientMode ? 'opacity-70' : ''}
                `}>
                    <div className={`transform transition-all duration-200 ${isSelected ? 'scale-100 opacity-100' : 'scale-0 opacity-0'}`}>
                         {isRadio ? <div className="w-2 h-2 bg-white rounded-full"></div> : <CheckIcon />}
                    </div>
                </div>

                <div className="flex-grow">
                    <div className="flex flex-col sm:flex-row justify-between sm:items-center">
                        <div className="flex items-center gap-3">
                            <h4 className={`font-bold transition-colors duration-300 ${isSelected ? 'text-blue-900' : 'text-slate-800'}`}>{option.name}</h4>
                        </div>
                        <div className={`font-semibold transition-colors duration-300 ${isSelected ? 'text-blue-900' : 'text-slate-900'} ${language === 'ar' ? 'sm:text-left' : 'sm:text-right'}`}>
                            {option.hasQuantity && quantity > 1 && !isClientMode ? (
                                <div>
                                    <p className="text-lg">${totalOptionPrice.toLocaleString()}</p>
                                    <p className="text-xs text-slate-500 font-normal mt-1">
                                        ({quantity} &times; ${currentUnitPrice.toLocaleString()})
                                    </p>
                                </div>
                            ) : (
                                <p className="text-lg">
                                    ${currentUnitPrice.toLocaleString()}
                                    {option.hasQuantity && <span className="text-sm text-slate-500 font-normal"> {option.priceSuffix || t.perPageSuffix}</span>}
                                </p>
                            )}
                        </div>
                    </div>

                    {option.items && (
                        <ul className={`mt-2 text-sm text-slate-600 space-y-1 ${language === 'ar' ? 'pr-4' : 'pl-4'} list-disc list-inside`}>
                            {option.items.map((item, index) => (
                                <li key={index} dangerouslySetInnerHTML={{ __html: item.replace(/__(.*?)__/g, '<strong>$1</strong>') }} />
                            ))}
                        </ul>
                    )}

                    <div className="mt-4 flex flex-wrap items-center gap-4">
                        {option.hasQuantity && !isClientMode && (
                            <QuantitySelector quantity={quantity} onQuantityChange={onQuantityChange} t={t} label={option.quantityLabel} />
                        )}
                    </div>
                </div>
            </div>

            {/* Print-only view */}
            {isSelected && (
                <div className="hidden print:block pt-2">
                    <div className="flex justify-between items-baseline">
                        <div className="flex items-center gap-2">
                           <h4 className="font-bold text-sm text-black">{option.name}</h4>
                        </div>
                        <p className="font-semibold text-sm text-black">
                            {option.hasQuantity ? `${quantity} x $${currentUnitPrice.toLocaleString()}` : `$${currentUnitPrice.toLocaleString()}`}
                        </p>
                    </div>
                    {option.hasQuantity && (
                        <div className="flex justify-end">
                            <p className="font-bold text-sm text-black">= ${totalOptionPrice.toLocaleString()}</p>
                        </div>
                    )}
                    {option.items && (
                        <ul className="mt-1 text-xs text-gray-700 space-y-0.5 list-disc list-inside">
                             {option.items.map((item, index) => (
                                <li key={index} dangerouslySetInnerHTML={{ __html: item.replace(/__(.*?)__/g, '<strong>$1</strong>') }} />
                            ))}
                        </ul>
                    )}
                </div>
            )}
        </div>
    );
};

export default PricingOption;

import React, { useState, useMemo, useEffect, useCallback, useRef } from 'react';
import Header from './components/Header';
import Footer from './components/Footer';
import StaticSection from './components/StaticSection';
import PricingSection from './components/PricingSection';
import TotalBar from './components/TotalBar';
import TermsAndConditions from './components/TermsAndConditions';
import { getServiceCategories, getUnitPrice } from './constants';
import { translations } from './i18n';
import type { ServiceOption, ServiceCategory } from './types';
import PrintHeader from './components/PrintHeader';
import SuccessScreen from './components/SuccessScreen';
import DiscountCelebration from './components/DiscountCelebration';
import { isEmailConfigured, sendProposalEmails } from './email';

const URL_PARAMS = new URLSearchParams(window.location.search);
const IS_CLIENT_MODE = URL_PARAMS.get('mode') === 'client' && URL_PARAMS.has('services');
const CLIENT_SERVICE_IDS = (URL_PARAMS.get('services') || '').split(',').filter(Boolean);

interface ClientInfo {
  name: string;
  phone: string;
  email: string;
  countryCode: string;
}

function getInitialLanguage() {
    const savedLang = localStorage.getItem('language');
    if (savedLang === 'en' || savedLang === 'ar') {
        return savedLang;
    }
    return 'ar';
}

function getInitialClientInfo(): ClientInfo {
    if (IS_CLIENT_MODE) {
        return {
            name: URL_PARAMS.get('name') || '',
            phone: URL_PARAMS.get('phone') || '',
            email: URL_PARAMS.get('email') || '',
            countryCode: URL_PARAMS.get('countryCode') || '+90',
        };
    }
    return { name: '', phone: '', email: '', countryCode: '+90' };
}

function App() {
  const [language, setLanguage] = useState<'ar' | 'en'>(getInitialLanguage());
  const [isClientMode] = useState(IS_CLIENT_MODE);
  const [clientInfo, setClientInfo] = useState<ClientInfo>(getInitialClientInfo);
  const [emailError, setEmailError] = useState('');
  const [formError, setFormError] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>(() => {
    if (IS_CLIENT_MODE) {
      return CLIENT_SERVICE_IDS;
    }
    return [];
  });
  const [quantities, setQuantities] = useState<{ [id: string]: number }>({});
  const [actionType, setActionType] = useState<string | null>(null);
  const [proposalDate] = useState(new Date());
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [showCelebration, setShowCelebration] = useState(false);

  // Use a ref to track the previous discount percentage to avoid extra renders
  const prevDiscountPercentageRef = useRef(0);

  const t = useMemo(() => translations[language], [language]);
  const serviceCategories = useMemo(() => {
    const allCategories = getServiceCategories(language);
    if (isClientMode && CLIENT_SERVICE_IDS.length > 0) {
      const clientCategories = allCategories
        .map(category => ({
          ...category,
          options: category.options.filter(option => CLIENT_SERVICE_IDS.includes(option.id)),
        }))
        .filter(category => category.options.length > 0);
      return clientCategories;
    }
    return allCategories;
  }, [language, isClientMode]);

  // Language side effect
  useEffect(() => {
    document.documentElement.lang = language;
    document.documentElement.dir = language === 'ar' ? 'rtl' : 'ltr';
    document.documentElement.classList.remove('lang-en', 'lang-ar');
    document.documentElement.classList.add(`lang-${language}`);
  }, [language]);

  const toggleLanguage = () => {
    const newLang = language === 'ar' ? 'en' : 'ar';
    setLanguage(newLang);
    localStorage.setItem('language', newLang);
  };

  const validateEmail = (email: string) => {
    if (email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      setEmailError(t.emailError);
    } else {
      setEmailError('');
    }
  };

  const handleClientInfoChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setClientInfo(prev => ({ ...prev, [name]: value }));
    if (formError) setFormError('');
    if (name === 'email') {
      validateEmail(value);
    }
  };

  const handleServiceToggle = (optionId: string, category: ServiceCategory) => {
    setSelectedIds(prevIds => {
      let newIds = [...prevIds];
      const isSelected = newIds.includes(optionId);

      if (category.isRadio) {
        // Deselect all options in this category first
        category.options.forEach(opt => {
          const index = newIds.indexOf(opt.id);
          if (index > -1) newIds.splice(index, 1);
        });
        // Then select the new one if it wasn't selected
        if (!isSelected) {
          newIds.push(optionId);
        }
      } else if (category.isPhased) {
        const selectedOptionIndex = category.options.findIndex(o => o.id === optionId);

        // First, clear all selections in this category
        category.options.forEach(opt => {
          const index = newIds.indexOf(opt.id);
          if (index > -1) newIds.splice(index, 1);
        });

        // If it was not currently selected, select it and all previous phases.
        // If it was selected, it is now deselected (cleared above).
        if (!isSelected) {
          for (let i = 0; i <= selectedOptionIndex; i++) {
            newIds.push(category.options[i].id);
          }
        }
      } else {
        if (isSelected) {
          newIds = newIds.filter(id => id !== optionId);
        } else {
          newIds.push(optionId);
        }
      }
      return newIds;
    });
  };

  const handleQuantityChange = (optionId: string, newQuantity: number) => {
    if (newQuantity >= 1) {
      setQuantities(prev => ({ ...prev, [optionId]: newQuantity }));
    }
  };

  const handleClearSelection = () => {
    if (isClientMode) return;
    setSelectedIds([]);
    setQuantities({});
  };

  const selectedOptions = useMemo(() => {
    const allOptions = serviceCategories.flatMap(c => c.options);
    return allOptions.filter(o => selectedIds.includes(o.id));
  }, [selectedIds, serviceCategories]);

  const subTotalPrice = useMemo(() => {
    return selectedOptions.reduce((total, option) => {
      const quantity = !isClientMode && option.hasQuantity ? (quantities[option.id] || 1) : 1;
      const unitPrice = getUnitPrice(option, quantity);
      return total + (unitPrice * quantity);
    }, 0);
  }, [selectedOptions, quantities, isClientMode]);

  const discountPercentage = useMemo(() => {
    if (isClientMode) return 0; // No discounts in client mode

    // 1. Tiered discount based on count of selected services
    let basePercentage = 0;
    const count = selectedIds.length;

    if (count >= 10) {
      basePercentage = 30;
    } else if (count >= 8) {
      basePercentage = 20;
    } else if (count >= 4) {
      basePercentage = 10;
    }

    // 2. Additional discount for high total price
    let bonusPercentage = 0;
    if (subTotalPrice > 5000) {
      bonusPercentage = 5;
    }

    return basePercentage + bonusPercentage;
  }, [selectedIds.length, isClientMode, subTotalPrice]);

  const discount = useMemo(() => (subTotalPrice * discountPercentage) / 100, [subTotalPrice, discountPercentage]);
  const finalTotalPrice = useMemo(() => subTotalPrice - discount, [subTotalPrice, discountPercentage]);

  // Logic to trigger celebratory animation when discount tier increases
  useEffect(() => {
    if (isClientMode) return;

    if (discountPercentage > prevDiscountPercentageRef.current) {
        setShowCelebration(true);
    }
    prevDiscountPercentageRef.current = discountPercentage;
  }, [discountPercentage, isClientMode]);

  const validateAdminInfo = useCallback(() => {
    const { name, phone, email } = clientInfo;
    const isEmailValid = email && !emailError;
    if (!name || !phone || !isEmailValid) {
      setFormError(t.fillInfoAlert);
      return false;
    }
    setFormError('');
    return true;
  }, [clientInfo, emailError, t.fillInfoAlert]);

  const validateClientInfo = useCallback(() => {
      const { name, phone, email } = clientInfo;
      const isEmailValid = email && !emailError;
      if (!name || !phone || !isEmailValid) {
        setFormError(t.fillInfoAlertClient);
        return false;
      }
      setFormError('');
      return true;
  }, [clientInfo, emailError, t.fillInfoAlertClient]);

  const handleSendViaWhatsApp = () => {
    setFormError('');
    if (!validateAdminInfo()) return;

    const formattedDate = proposalDate.toLocaleDateString(language === 'ar' ? 'ar-EG' : 'en-US', {
        year: 'numeric',
        month: 'long',
        day: 'numeric',
    });

    const formatPrice = (price: number) => `$${price.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
    const fullPhoneNumber = `${clientInfo.countryCode}${clientInfo.phone}`;

    const servicesText = selectedOptions.map(option => {
        const quantity = option.hasQuantity ? (quantities[option.id] || 1) : 1;
        const unitPrice = getUnitPrice(option, quantity);
        const price = unitPrice * quantity;
        const quantityText = option.hasQuantity ? ` (${quantity} × ${formatPrice(unitPrice).replace('$', '')})` : '';
        return `- ${option.name}${quantityText}: *${formatPrice(price)}*`;
    }).join('\n');

    const message = `
*${t.proposalTitle}*

*${t.clientInfoTitle}:*
${t.clientNameLabel}: ${clientInfo.name}
${t.clientPhoneLabel}: ${fullPhoneNumber}
${t.clientEmailLabel}: ${clientInfo.email}
${t.proposalDateLabel}: ${formattedDate}

*${t.selectedServicesTitle}:*
${servicesText}

*${t.priceSummaryTitle}:*
${t.subtotal}: ${formatPrice(subTotalPrice)}
${language === 'en' ? t.discountLabel(discountPercentage) : `خصم (${discountPercentage}%)`}: -${formatPrice(discount)}
*${t.totalPrice}: ${formatPrice(finalTotalPrice)}*

${t.proposalTo(clientInfo.name)}
    `.trim().replace(/^\s+/gm, "");

    const whatsappNumber = '+905342006606';
    const encodedMessage = encodeURIComponent(message);
    const whatsappUrl = `https://wa.me/${whatsappNumber}?text=${encodedMessage}`;

    window.open(whatsappUrl, '_blank', 'noopener,noreferrer');
};


  const handleClientSubmission = () => {
    setFormError('');
    if (!validateClientInfo() || actionType) return;

    if (!isEmailConfigured()) {
        setFormError(t.emailConfigMissing);
        return;
    }

    setActionType('email');

    sendProposalEmails({
      clientInfo,
      selectedOptions,
      quantities,
      subTotalPrice,
      discount,
      discountPercentage,
      finalTotalPrice,
      isClientSubmission: true,
      t,
      selectedIds,
      proposalDate
    })
      .then((response) => {
        console.log('SUCCESS! Both emails sent on client submission.', response);
        setShowSuccessScreen(true);
        setActionType(null);
      }, (err) => {
        console.error('FAILED... EmailJS Error on client submission:', err);
        let userMessage = t.emailSendError;
        if (err && typeof err.status === 'number') {
            if (err.status === 400) {
                userMessage = t.emailSendErrorConfig;
            } else if (err.status === 0) {
                userMessage = t.emailSendErrorNetwork;
            }
        }
        setFormError(userMessage);
        setActionType(null);
      });
  };

  const handleCloseSuccessScreen = () => {
    setShowSuccessScreen(false);
  };

  return (
    <div className="bg-transparent min-h-screen">
      <Header 
        language={language}
        toggleLanguage={toggleLanguage}
      />
      <PrintHeader />
      <main className="max-w-4xl mx-auto p-4 md:p-8 space-y-8 print:p-0 print:mx-0 print:max-w-full">
        <StaticSection 
          t={t}
          language={language}
          clientInfo={clientInfo}
          onClientInfoChange={handleClientInfoChange}
          emailError={emailError}
          proposalDate={proposalDate}
          isClientMode={isClientMode}
        />
        <PricingSection
          categories={serviceCategories}
          selectedIds={selectedIds}
          onServiceToggle={handleServiceToggle}
          quantities={quantities}
          onQuantityChange={handleQuantityChange}
          language={language}
          t={t}
          isClientMode={isClientMode}
        />
        <TermsAndConditions t={t} language={language} />
      </main>
      <Footer />
      <TotalBar
        subTotalPrice={subTotalPrice}
        finalTotalPrice={finalTotalPrice}
        discount={discount}
        discountPercentage={discountPercentage}
        onSendEmail={isClientMode ? handleClientSubmission : handleSendViaWhatsApp}
        onClearSelection={handleClearSelection}
        language={language}
        t={t}
        actionType={actionType}
        formError={formError}
        isClientMode={isClientMode}
      />
      {showSuccessScreen && (
        <SuccessScreen 
            t={t}
            isClientMode={isClientMode}
            onClose={handleCloseSuccessScreen}
        />
      )}
      {showCelebration && (
        <DiscountCelebration 
            t={t}
